import 'bootstrap/dist/css/bootstrap.min.css';
import './css/home.css'

export default function Home(){
    return (
        <div className="Home">
                <section className='main-page' id='main-page-id'>
                    <div className='container'>
                        <div className='text-main-page'>
                            <div className='col-md-12'>
                                <p className='name'>Jorge <span className='name-p1'>Alexis</span> <span className='name-p1'>M</span>árquez <span className='name-p1'>Rosales</span></p>  
                                <p>
                                Lorem ipsum dolor sit amet, consectetur adipiscing elit. Morbi faucibus ut dui commodo aliquam. Duis non ipsum posuere, viverra lorem pellentesque, semper elit. Proin pellentesque, mi eu convallis interdum, mi ipsum pellentesque urna, ut aliquet orci velit eu lorem. Vestibulum vel ligula vitae ipsum pharetra lacinia at eu orci. Quisque aliquet, justo nec consequat rutrum, odio sapien commodo tortor, id vestibulum elit elit ut lorem. Ut id nisi finibus magna pellentesque convallis. Quisque dignissim placerat enim placerat dictum. Cras gravida ipsum elit, sit amet interdum nibh volutpat sed. Integer sed mattis mi. Donec vitae tellus sapien. Integer maximus, sem facilisis volutpat gravida, mi dui convallis lorem, vitae dictum dui leo eget lorem. Vivamus tincidunt in mi quis hendrerit. Suspendisse tempor nulla diam, et ornare felis accumsan at.

                                Mauris commodo, arcu quis iaculis luctus, quam diam pulvinar arcu, nec faucibus enim sapien nec ex. Nulla fermentum magna vel gravida semper. In accumsan magna rhoncus, pharetra orci vitae, faucibus orci. Sed egestas elit eget sapien dictum, non tincidunt ante dapibus. Proin tristique risus eget nisi malesuada congue in in risus. Integer tristique neque nec blandit cursus. Quisque nec interdum sapien. Cras ac magna cursus, finibus neque nec, tristique turpis. Mauris condimentum rutrum magna nec porta. Morbi turpis purus, imperdiet vitae vehicula in, consectetur eu massa. Maecenas venenatis eros at convallis consectetur. Maecenas quam quam, porta sed magna vel, malesuada semper nulla. Aenean sollicitudin tristique dui a maximus. Sed maximus lorem rutrum sapien pharetra, eu porttitor nisl condimentum. Duis id mauris augue.
                                </p>  
                            </div>
                        </div>
                    </div>
                </section>
                <section className='projects-page'>
                    <div className='container'>
                        <div className='row'>
                            <div className='col-md-12'>

                            </div>
                        </div>
                    </div>
                </section>
        </div>
    )
}

window.addEventListener('scroll', function() {
    var nav = document.querySelector('.nav');
    var section = document.querySelector('#main-page-id');
    if (window.scrollY >= section.offsetTop + section.offsetHeight) {
      nav.classList.add('shadow');
    } else {
      nav.classList.remove('shadow');
    }
});
